import Stripe from 'stripe';

const key = process.env['STRIPE_SECRET_KEY'];
if (!key) throw new Error('STRIPE_SECRET_KEY environment variable is not set.');

export const stripe = new Stripe(key, {
  apiVersion: '2024-04-10',
  typescript: true,
});

import type { Request, Response } from 'express';
import { stripe } from './stripe.js';

/**
 * Express handler for the Stripe webhook endpoint.
 * Mount with: app.post('/webhooks/stripe', express.raw({ type: 'application/json' }), handleStripeWebhook)
 */
export async function handleStripeWebhook(req: Request, res: Response): Promise<void> {
  const sig = req.headers['stripe-signature'];
  const secret = process.env['STRIPE_WEBHOOK_SECRET'];

  if (!sig || !secret) {
    res.status(400).send('Missing Stripe signature or webhook secret.');
    return;
  }

  let event: import('stripe').Stripe.Event;
  try {
    event = stripe.webhooks.constructEvent(req.body as Buffer, sig, secret);
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    res.status(400).send(`Webhook signature verification failed: ${message}`);
    return;
  }

  // Route events to handlers
  switch (event.type) {
    case 'checkout.session.completed': {
      // const session = event.data.object;
      // TODO: fulfil the purchase
      break;
    }
    case 'customer.subscription.deleted': {
      // const subscription = event.data.object;
      // TODO: revoke access
      break;
    }
    default:
      // Unhandled event type — safe to ignore
      break;
  }

  res.json({ received: true });
}

export type { Stripe } from 'stripe';

/** Common Stripe event types used in webhook handlers. */
export type StripeEventType =
  | 'checkout.session.completed'
  | 'customer.subscription.created'
  | 'customer.subscription.updated'
  | 'customer.subscription.deleted'
  | 'invoice.payment_succeeded'
  | 'invoice.payment_failed';

export type StripeWebhookEvent = import('stripe').Stripe.Event;
